124	func (f *CommandFactory) newAgentRunCommand() *cobra.Command {
125		cmd := &cobra.Command{
126			Use:          "run",
127			Short:        "Invoke an agent with a prompt",
128			SilenceUsage: true,
129			RunE: func(cmd *cobra.Command, args []string) error {
130				promptFile, _ := cmd.Flags().GetString("prompt")
131				promptText, _ := cmd.Flags().GetString("text")
132				harness, _ := cmd.Flags().GetString("harness")
133				model, _ := cmd.Flags().GetString("model")
134				profile, _ := cmd.Flags().GetString("profile")
135				effort, _ := cmd.Flags().GetString("effort")
136				timeoutStr, _ := cmd.Flags().GetString("timeout")
137				quorum, _ := cmd.Flags().GetString("quorum")
138				harnesses, _ := cmd.Flags().GetString("harnesses")
139				asJSON, _ := cmd.Flags().GetBool("json")
140				outputFmt, _ := cmd.Flags().GetString("output")
141				worktreeName, _ := cmd.Flags().GetString("worktree")
142				permissions, _ := cmd.Flags().GetString("permissions")
143				compare, _ := cmd.Flags().GetBool("compare")
144				sandbox, _ := cmd.Flags().GetBool("sandbox")
145				keepSandbox, _ := cmd.Flags().GetBool("keep-sandbox")
146				postRun, _ := cmd.Flags().GetString("post-run")
147				arms, _ := cmd.Flags().GetStringArray("arm")
148	
149				var timeout time.Duration
150				if timeoutStr != "" {
151					var err error
152					timeout, err = time.ParseDuration(timeoutStr)
153					if err != nil {
154						return fmt.Errorf("invalid timeout: %w", err)
155					}
156				}
157	
158				// Resolve project root (--project flag > DDX_PROJECT_ROOT > CWD git root)
159				projectFlag, _ := cmd.Flags().GetString("project")
160				workDir := resolveProjectRoot(projectFlag, f.WorkingDir)
161				if worktreeName != "" {
162					wtPath, err := resolveWorktree(workDir, worktreeName)
163					if err != nil {
164						return fmt.Errorf("worktree: %w", err)
165					}
166					workDir = wtPath
167				}
168	
169				// Read prompt from stdin if neither file nor text provided
170				prompt := promptText
171				promptSource := "inline"
172				if prompt == "" && promptFile == "" {
173					// Check if stdin has data
174					stat, _ := os.Stdin.Stat()
175					if (stat.Mode() & os.ModeCharDevice) == 0 {
176						data, err := io.ReadAll(os.Stdin)
177						if err != nil {
178							return fmt.Errorf("reading stdin: %w", err)
179						}
180						prompt = string(data)
181						promptSource = "stdin"
182					}
183				} else if promptFile != "" {
184					promptSource = promptFile
185				}
186	
187				// Comparison mode
188				if compare {
189					var harnessNames []string
190					armModels := map[int]string{}
191					armLabels := map[int]string{}
192	
193					// Parse --arm flags: "harness:model:label" or "harness:model" or "harness"
194					if len(arms) > 0 {
195						for i, arm := range arms {
196							parts := strings.SplitN(arm, ":", 3)
197							harnessNames = append(harnessNames, parts[0])
198							if len(parts) >= 2 && parts[1] != "" {
199								armModels[i] = parts[1]
200							}
201							if len(parts) >= 3 {
202								armLabels[i] = parts[2]
203							} else if len(parts) >= 2 && parts[1] != "" {
204								armLabels[i] = parts[0] + "/" + parts[1]
205							}
206						}
207					} else if harnesses != "" {
208						harnessNames = strings.Split(harnesses, ",")
209					} else {
210						return fmt.Errorf("--arm or --harnesses required for --compare mode")
211					}
212	
213					overrides := config.CLIOverrides{
214						Model:       model,
215						Effort:      effort,
216						Permissions: permissions,
217					}
218					if timeout > 0 {
219						overrides.Timeout = &timeout
220					}
221					rcfg, _ := config.LoadAndResolve(f.WorkingDir, overrides)
222					runtime := agent.CompareRuntime{
223						AgentRunRuntime: agent.AgentRunRuntime{
224							Prompt:       prompt,
225							PromptFile:   promptFile,
226							PromptSource: promptSource,
227							WorkDir:      workDir,
228						},
229						Harnesses:   harnessNames,
230						ArmModels:   armModels,
231						ArmLabels:   armLabels,
232						Sandbox:     sandbox,
233						KeepSandbox: keepSandbox,
234						PostRun:     postRun,
235					}
236					record, err := agent.RunCompareWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
237					if err != nil {
238						return err
239					}
240					if asJSON {
241						enc := json.NewEncoder(cmd.OutOrStdout())
242						enc.SetIndent("", "  ")
243						return enc.Encode(record)
244					}
245					fmt.Fprintf(cmd.OutOrStdout(), "Comparison %s (%d arms)\n", record.ID, len(record.Arms))
246					for _, arm := range record.Arms {
247						status := "OK"
248						if arm.ExitCode != 0 {
249							status = fmt.Sprintf("FAIL (rc=%d)", arm.ExitCode)
250						}
251						cost := ""
252						if arm.CostUSD > 0 {
253							cost = fmt.Sprintf(" cost=$%.4f", arm.CostUSD)
254						}
255						fmt.Fprintf(cmd.OutOrStdout(), "  %-12s %s  tokens=%d  duration=%dms%s\n",
256							arm.Harness, status, arm.Tokens, arm.DurationMS, cost)
257						if arm.Diff != "" {
258							lines := strings.Count(arm.Diff, "\n")
259							fmt.Fprintf(cmd.OutOrStdout(), "             diff: %d lines\n", lines)
260						}
261					}
262					return nil
263				}
264	
265				// Quorum mode
266				if quorum != "" || harnesses != "" {
267					harnessNames := strings.Split(harnesses, ",")
268					if len(harnessNames) == 0 || (len(harnessNames) == 1 && harnessNames[0] == "") {
269						return fmt.Errorf("--harnesses required for quorum mode")
270					}
271					overrides := config.CLIOverrides{
272						Model:       model,
273						Effort:      effort,
274						Permissions: permissions,
275					}
276					if timeout > 0 {
277						overrides.Timeout = &timeout
278					}
279					rcfg, _ := config.LoadAndResolve(f.WorkingDir, overrides)
280					runtime := agent.QuorumRuntime{
281						AgentRunRuntime: agent.AgentRunRuntime{
282							Prompt:       prompt,
283							PromptFile:   promptFile,
284							PromptSource: promptSource,
285							WorkDir:      workDir,
286						},
287						Harnesses: harnessNames,
288						Strategy:  quorum,
289					}
290					results, err := agent.RunQuorumWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
291					if err != nil {
292						return err
293					}
294					met := agent.QuorumMet(quorum, 0, results)
295					if asJSON {
296						enc := json.NewEncoder(cmd.OutOrStdout())
297						enc.SetIndent("", "  ")
298						return enc.Encode(map[string]any{
299							"quorum_met": met,
300							"strategy":   quorum,
301							"results":    results,
302						})
303					}
304					for _, result := range results {
305						if result == nil {
306							continue
307						}
308						fmt.Fprintf(cmd.OutOrStdout(), "[%s] rc=%d tokens=%d duration=%dms\n",
309							result.Harness, result.ExitCode, result.Tokens, result.DurationMS)
310						if result.CondensedOutput != "" {
311							fmt.Fprintln(cmd.OutOrStdout(), result.CondensedOutput)
312						} else if result.Output != "" {
313							fmt.Fprintln(cmd.OutOrStdout(), result.Output)
314						}
315					}
316					if met {
317						fmt.Fprintf(cmd.OutOrStdout(), "Quorum: MET (%s)\n", quorum)
318					} else {
319						fmt.Fprintf(cmd.OutOrStdout(), "Quorum: NOT MET (%s)\n", quorum)
320						return fmt.Errorf("quorum not met")
321					}
322					return nil
323				}
324	
325				// Single harness mode (ddx-755f5881 D1+D5):
326				// When neither --harness nor agent.harness in config pins a
327				// specific harness, issue exactly one ResolveRoute call with the
328				// (normalized) Profile and let upstream pick the harness/model.
329				// No DDx-side ladder iteration, no ResolveTierModelRef lookup,
330				// no preference-order fallback. The default profile is "default".
331				//
332				// When agent.harness is set in config, fall through to
333				// LoadAndResolve below — that path already plumbs the configured
334				// harness into rcfg.Harness() (SD-024 Stage 2 contract).
335				configHarness := ""
336				if cfg, _ := config.LoadWithWorkingDir(f.WorkingDir); cfg != nil && cfg.Agent != nil {
337					configHarness = strings.TrimSpace(cfg.Agent.Harness)
338				}
339				resolvedHarness := harness
340				resolvedModel := model
341				resolvedProvider := ""
342				if harness == "" && configHarness == "" {
343					profile = agent.NormalizeRoutingProfile(profile)
344					svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
345					if svcErr != nil {
346						return fmt.Errorf("agent: failed to initialize routing service: %w", svcErr)
347					}
348					routeReq := agentlib.RouteRequest{
349						Profile:     profile,
350						Model:       model,
351						Reasoning:   agentlib.Reasoning(effort),
352						Permissions: permissions,
353					}
354					recordRouteRequestForTest(routeReq)
355					dec, routeErr := svc.ResolveRoute(cmd.Context(), routeReq)
356					if routeErr != nil {
357						return fmt.Errorf("agent: no viable harness found for profile %q: %w", profile, routeErr)
358					}
359					resolvedHarness = dec.Harness
360					resolvedProvider = dec.Provider
361					if model == "" && dec.Model != "" {
362						resolvedModel = dec.Model
363					}
364					if resolvedHarness == "" {
365						return fmt.Errorf("agent: no viable harness found for profile %q; install a harness or use --harness to specify one", profile)
366					}
367				}
368	
369				overrides := config.CLIOverrides{
370					Harness:     resolvedHarness,
371					Model:       resolvedModel,
372					Provider:    resolvedProvider,
373					Effort:      effort,
374					Permissions: permissions,
375				}
376				if timeout > 0 {
377					overrides.Timeout = &timeout
378				}
379				rcfg, _ := config.LoadAndResolve(f.WorkingDir, overrides)
380				runtime := agent.AgentRunRuntime{
381					Prompt:       prompt,
382					PromptFile:   promptFile,
383					PromptSource: promptSource,
384					WorkDir:      workDir,
385				}
386				result, err := agent.RunWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
387				if err != nil {
388					return err
389				}
390	
391				// Record the prompt→response pair for virtual harness replay.
392				if record, _ := cmd.Flags().GetBool("record"); record && result.ExitCode == 0 {
393					resolvedPrompt := prompt
394					if resolvedPrompt == "" && promptFile != "" {
395						data, _ := os.ReadFile(promptFile)
396						resolvedPrompt = string(data)
397					}
398					entry := &agent.VirtualEntry{
399						Prompt:       resolvedPrompt,
400						Response:     result.Output,
401						Harness:      result.Harness,
402						Model:        result.Model,
403						DelayMS:      result.DurationMS,
404						InputTokens:  result.InputTokens,
405						OutputTokens: result.OutputTokens,
406						CostUSD:      result.CostUSD,
407					}
408					dictDir := agent.VirtualDictionaryDir
409					// Load normalization patterns from config.
410					var patterns []config.NormalizePattern
411					if cfg, cfgErr := config.Load(); cfgErr == nil && cfg.Agent != nil && cfg.Agent.Virtual != nil {
412						patterns = cfg.Agent.Virtual.Normalize
413					}
414					if err := agent.RecordEntry(dictDir, entry, patterns...); err != nil {
415						fmt.Fprintf(os.Stderr, "Warning: failed to record response: %v\n", err)
416					} else {
417						normalized := agent.NormalizePrompt(resolvedPrompt, patterns)
418						fmt.Fprintf(os.Stderr, "Recorded response → %s/%s.json\n", dictDir, agent.PromptHash(normalized))
419					}
420				}
421	
422				// --json is a backward-compatible alias for --output json-result
423				if asJSON {
424					outputFmt = "json-result"
425				}
426				switch outputFmt {
427				case "json-result":
428					enc := json.NewEncoder(cmd.OutOrStdout())
429					enc.SetIndent("", "  ")
430					if err := enc.Encode(result); err != nil {
431						return err
432					}
433				case "session-jsonl":
434					if result.CondensedOutput != "" {
435						fmt.Fprint(cmd.OutOrStdout(), result.CondensedOutput)
436					} else if result.Output != "" {
437						fmt.Fprint(cmd.OutOrStdout(), result.Output)
438					}
439				case "text":
440					text := agent.ExtractOutput(result.Harness, result.Output)
441					if text != "" {
442						fmt.Fprint(cmd.OutOrStdout(), text)
443					}
444				default:
445					return fmt.Errorf("unknown --output value %q (valid: text, json-result, session-jsonl)", outputFmt)
446				}
447				if result.ExitCode != 0 {
448					msg := fmt.Sprintf("agent exited with code %d", result.ExitCode)
449					if result.Error != "" {
450						msg += "\n  error: " + result.Error

450						msg += "\n  error: " + result.Error
451					}
452					if result.Stderr != "" && result.Stderr != result.Error {
453						// Show at most 5 stderr lines to surface auth/rate-limit diagnostics
454						// without flooding the terminal with full agent output.
455						lines := strings.SplitN(strings.TrimSpace(result.Stderr), "\n", 6)
456						if len(lines) > 5 {
457							lines = append(lines[:5], "  ...")
458						}
459						msg += "\n  stderr:\n    " + strings.Join(lines, "\n    ")
460					}
461					return fmt.Errorf("%s", msg)
462				}
463				return nil
464			},
465		}
