491	func (f *CommandFactory) newAgentCondenseCommand() *cobra.Command {
492		cmd := &cobra.Command{
493			Use:   "condense",
494			Short: "Filter raw agent output to progress-relevant lines",
495			Long: `Read raw agent output from stdin and write condensed output to stdout.
496	
497	Keeps: namespace-prefixed progress lines, tool calls, errors/warnings, issue IDs,
498	markdown structure (#, |, **), and phase markers. Drops raw diffs, codex
499	boilerplate (Commands run:, tokens used), and bulk verbose content.`,
500			RunE: func(cmd *cobra.Command, args []string) error {
501				namespace, _ := cmd.Flags().GetString("namespace")
502				data, err := io.ReadAll(os.Stdin)
503				if err != nil {
504					return fmt.Errorf("reading stdin: %w", err)
505				}
506				result := agent.CondenseOutput(string(data), namespace)
507				if result != "" {
508					fmt.Fprint(cmd.OutOrStdout(), result)
509					if !strings.HasSuffix(result, "\n") {
510						fmt.Fprintln(cmd.OutOrStdout())
511					}
512				}
513				return nil
514			},
515		}
516		cmd.Flags().String("namespace", "helix:", "Caller namespace prefix to keep (e.g. helix:)")
517		return cmd
518	}
