520	func (f *CommandFactory) newAgentListCommand() *cobra.Command {
521		cmd := &cobra.Command{
522			Use:   "list",
523			Short: "List available agent harnesses",
524			Args:  cobra.NoArgs,
525			RunE: func(cmd *cobra.Command, args []string) error {
526				svc, err := agent.NewServiceFromWorkDir(f.WorkingDir)
527				if err != nil {
528					return fmt.Errorf("constructing agent service: %w", err)
529				}
530	
531				ctx := context.Background()
532				harnesses, err := svc.ListHarnesses(ctx)
533				if err != nil {
534					return fmt.Errorf("listing harnesses: %w", err)
535				}
536	
537				asJSON, _ := cmd.Flags().GetBool("json")
538				if asJSON {
539					type harnessEntry struct {
540						Name      string `json:"name"`
541						Type      string `json:"type,omitempty"`
542						Available bool   `json:"available"`
543						Path      string `json:"path,omitempty"`
